        imageUrls.forEach((url, index) => {
            userContent.push({ type: "image_url", image_url: { url: url } });
        });
    }

    const messages = [
        { role: "system", content: systemInstruction },
        { role: "user", content: userContent }
    ];

    try {
        const response = await fetch(`${creds.baseUrl}/chat/completions`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${creds.apiKey}`
            },
            body: JSON.stringify({
                model: MODEL_REASONING,
                messages: messages,
                max_tokens: 1500, // Increased for image analysis
                temperature: 0.7,
                response_format: { type: "json_object" } 
            }),
            credentials: 'omit'
        });

        if (!response.ok) throw new Error("Prompt Optimization failed");

        const data = await response.json();
        const content = data.choices?.[0]?.message?.content;

        if (!content) {
             throw new Error("API trả về nội dung rỗng.");
        }

        // --- Robust JSON Extraction ---
        let parsed;
        try {
            const cleanContent = content.replace(/```json/g, '').replace(/```/g, '').trim();
            parsed = JSON.parse(cleanContent);
        } catch (parseError) {
            console.warn("Standard JSON parse failed, attempting substring extraction...");
            const firstOpen = content.indexOf('{');
            const lastClose = content.lastIndexOf('}');

            if (firstOpen !== -1 && lastClose !== -1) {
                const jsonSubstring = content.substring(firstOpen, lastClose + 1);
                parsed = JSON.parse(jsonSubstring);
            } else {
                throw new Error("Không tìm thấy JSON hợp lệ trong phản hồi.");
            }
        }

        return {
            english: parsed.english || userPrompt,
            vietnamese: parsed.vietnamese || "Không thể dịch."
        };

    } catch (e) {
        console.warn("Creative Prompt Optimization Warning:", e);

        const msg = e instanceof Error ? e.message : String(e);
        let reason = "Lỗi xử lý dữ liệu (JSON).";

        if (msg.includes("Failed to fetch") || msg.includes("NetworkError")) {
             reason = "Lỗi kết nối hoặc CORS.";
        } else if (msg.includes("413")) {
            reason = "Ảnh quá nặng, vui lòng giảm dung lượng.";
        }

        return { 
            english: userPrompt, 
            vietnamese: `⚠️ Không thể tối ưu hóa tự động (${reason}). Đang sử dụng prompt gốc.` 
        };
    }
};

