        const content = data.choices?.[0]?.message?.content;

        if (!content) {
             throw new Error("API trả về nội dung rỗng.");
        }

        // --- Robust JSON Extraction ---
        let parsed;
        try {
            const cleanContent = content.replace(/```json/g, '').replace(/```/g, '').trim();
            parsed = JSON.parse(cleanContent);
        } catch (parseError) {
            console.warn("Standard JSON parse failed, attempting substring extraction...");
            const firstOpen = content.indexOf('{');
            const lastClose = content.lastIndexOf('}');

            if (firstOpen !== -1 && lastClose !== -1) {
                const jsonSubstring = content.substring(firstOpen, lastClose + 1);
                parsed = JSON.parse(jsonSubstring);
            } else {
                throw new Error("Không tìm thấy JSON hợp lệ trong phản hồi.");
            }
        }

        return {
            english: parsed.english || userPrompt,
            vietnamese: parsed.vietnamese || "Không thể dịch."
