    } catch (e) {
        console.warn("Creative Prompt Optimization Warning:", e);

        const msg = e instanceof Error ? e.message : String(e);
        let reason = "Lỗi xử lý dữ liệu (JSON).";

        if (msg.includes("Failed to fetch") || msg.includes("NetworkError")) {
             reason = "Lỗi kết nối hoặc CORS.";
        } else if (msg.includes("413")) {
            reason = "Ảnh quá nặng, vui lòng giảm dung lượng.";
