import { AspectRatio, Resolution, GenerationMode, ApiCredentials, MotionStrength, ContextRole, CreativePromptResult } from "../types";
import { MODEL_REASONING, MODEL_IMAGE_BASE } from "../constants";

// Helper to convert file to Data URL
export const fileToDataUrl = async (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      resolve(reader.result as string);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const handleFetchError = (error: unknown, baseUrl: string) => {
    const msg = error instanceof Error ? error.message : String(error);
    if (msg.includes("Failed to fetch") || msg.includes("NetworkError")) {
        if (window.location.protocol === 'https:' && baseUrl.startsWith('http://')) {
            throw new Error(`Lỗi kết nối (Mixed Content): Trình duyệt chặn gọi HTTP API từ trang HTTPS. Vui lòng dùng Ngrok (HTTPS) hoặc chạy App ở localhost.`);
        }
        throw new Error(`Lỗi kết nối đến Server (${baseUrl}). Vui lòng kiểm tra CORS hoặc Server có đang chạy không.`);
    }
    throw error;
};

// Helper to handle AI Model specific errors (Capacity, Quota)
const handleModelError = async (response: Response) => {
    const errText = await response.text();
    // Check for standard 429 or specific Google RPC error details in body
    if (
        response.status === 429 || 
        errText.includes("RESOURCE_EXHAUSTED") || 
        errText.includes("No capacity available") ||
        errText.includes("Too Many Requests")
    ) {
        throw new Error("⚠️ Server Google đang quá tải (Hết slot Model hoặc Quota). Vui lòng thử lại sau 30 giây hoặc chuyển về 1K.");
    }

    // Handle 502 from proxies that wrap the 429 error
    if (response.status === 502 && (errText.includes("429") || errText.includes("Upstream error"))) {
         throw new Error("⚠️ Server Proxy quá tải. Vui lòng thử lại sau.");
    }

    throw new Error(`Lỗi API (${response.status}): ${errText.substring(0, 300)}...`);
};

// Map MotionStrength enum to numerical denoising strength (0.0 to 1.0)
const getDenoisingStrength = (strength: MotionStrength): number => {
    switch (strength) {
        case MotionStrength.LOW: return 0.55;    // Tăng nhẹ để giữ nét tốt hơn
        case MotionStrength.MEDIUM: return 0.70; // Đủ để thay đổi pose
        case MotionStrength.HIGH: return 0.90;   // Thay đổi lớn (quay đầu, góc máy mới)
        default: return 0.70;
    }
};

// NEW: Helper to map AspectRatio to OpenAI 'size' string (Antigravity/OpenAI Standard)
const getOpenAISize = (ratio: AspectRatio): string => {
    switch (ratio) {
        // Landscape (Ngang)
        case AspectRatio.R_16_9: return "1920x1080"; 
        case AspectRatio.R_21_9: return "2560x1080"; 
        case AspectRatio.R_4_3: return "1440x1080"; 
        case AspectRatio.R_3_2: return "1620x1080"; 
        case AspectRatio.R_2_3: return "1080x1620";
        case AspectRatio.R_4_5: return "1080x1350";
        case AspectRatio.R_5_4: return "1350x1080";

        // Portrait (Dọc)
        case AspectRatio.R_9_16: return "1080x1920";
        case AspectRatio.R_3_4: return "1080x1440"; 

        // Square
        case AspectRatio.R_1_1: return "1024x1024";
        default: return "1024x1024";
    }
};

/**
 * Step 1: VISUAL DNA EXTRACTION & DIRECTOR AGENT
 * (Legacy function for Director Mode)
 */
export const enhancePromptWithMotion = async (
  creds: ApiCredentials,
  prompt: string,
  duration: number,
  mode: GenerationMode,
  referenceImageDataUrl: string,
  contextImages: { url: string; role: ContextRole }[] = []
): Promise<string> => {

  const isForward = mode === GenerationMode.FIRST_TO_LAST;
  const targetFrameName = isForward ? 'LAST FRAME' : 'FIRST FRAME';
  const inputFrameName = isForward ? 'FIRST FRAME' : 'LAST FRAME';

  const systemInstruction = `You are an expert AI Video Director.

  CONTEXT:
  - Input Image: ${inputFrameName} of a video clip.
  - User Intent: Describes the action happening in the clip.
  - DURATION: ${duration} seconds.

  VISUAL REFERENCES (Important):
  User has provided extra images with specific ROLES. You MUST strictly adhere to these roles when describing the subject/scene:
  - Role "face": The final character MUST look like this person. Mention specific facial features from this ref.
  - Role "background": The scene MUST take place in this environment.
  - Role "outfit": The character MUST wear these clothes.
  - Role "style": Copy the lighting, color grade, and artistic style.
  - Role "pose": The character should mimic this body language.

  MODE: ${isForward ? "FORWARD (Cause -> Effect)" : "REVERSE / PREQUEL (Effect -> Cause)"}

  CRITICAL THINKING:
  1.  **Visual DNA Integration:** Look at the 'face'/'outfit' context images (if any) and explicitly describe those features in the final prompt to ensure consistency.
  2.  **Duration Logic (${duration}s):**
      - 5s: Short duration. Movement is contained.
      - 15s: Long duration. Complete change in state/location.
  3.  **Camera & Atmosphere:**
      - Inject specific camera movements (Pan, Zoom, Tilt, Tracking).

  OUTPUT FORMAT:
  "[SUBJECT STATE]: {Visual description of the subject in the ${targetFrameName}, incorporating details from Context Images}
   [CAMERA]: {Camera movement keyword}
   [VISUAL DNA]: {Specific details extracted from FACE/OUTFIT context images}
   [ENV]: {Background details from BACKGROUND context image}
   [LIGHTING]: {Atmosphere from STYLE context image}"

  Output ONLY the final prompt.`;

  const userContent: any[] = [
    { type: "text", text: `MAIN REFERENCE (${inputFrameName}):` },
    { type: "image_url", image_url: { url: referenceImageDataUrl } }
  ];

  if (contextImages.length > 0) {
    userContent.push({ type: "text", text: "--- ADDITIONAL VISUAL CONTEXT ---" });
    contextImages.forEach((img, idx) => {
        userContent.push({ 
            type: "text", 
            text: `[Context Image ${idx + 1}] ROLE: ${img.role.toUpperCase()} (Use this image specifically for ${img.role} details)` 
        });
        userContent.push({ type: "image_url", image_url: { url: img.url } });
    });
    userContent.push({ type: "text", text: "--- END CONTEXT ---" });
  }

  userContent.push({ 
      type: "text", 
      text: `ACTION DESCRIPTION: "${prompt}"\nDURATION: ${duration} seconds.\n\nTask: Describe the ${targetFrameName} purely visually, blending the Main Ref with the specific details from Context Images.` 
  });

  const messages: any[] = [
    { role: "system", content: systemInstruction },
    { role: "user", content: userContent }
  ];

  try {
    const response = await fetch(`${creds.baseUrl}/chat/completions`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${creds.apiKey}`
      },
      body: JSON.stringify({
        model: MODEL_REASONING,
        messages: messages,
        max_tokens: 1500,
        temperature: 0.7 
      }),
      credentials: 'omit'
    });

    if (!response.ok) {
        console.warn(`Reasoning API Error: ${response.status}`);
        return prompt;
    }

    const data = await response.json();
    const enhanced = data.choices?.[0]?.message?.content;
    return enhanced || prompt;

  } catch (error) {
    console.error("Prompt optimization failed:", error);
    const msg = error instanceof Error ? error.message : String(error);
    if (msg.includes("Failed to fetch") || msg.includes("NetworkError")) {
         handleFetchError(error, creds.baseUrl);
    }
    return prompt; 
  }
};

/**
 * Step 2: GENERATE FRAME WITH DENOISING STRENGTH
 * (Legacy function for Director Mode)
 */
export const generateVideoFrame = async (
  creds: ApiCredentials,
  enhancedPrompt: string,
  aspectRatio: AspectRatio,
  resolution: Resolution,
  referenceImageDataUrl: string, 
  motionStrength: MotionStrength,
  contextImageDataUrls: string[] = []
): Promise<string> => {

  // 1. Correct Suffix Order: Ratio -> Resolution
  // Docs: gemini-3-pro-image-[比例]-[质量]
  // Example: gemini-3-pro-image-16-9-4k
  const ratioPart = aspectRatio.replace(':', '-');
  let resPart = '';
  if (resolution === Resolution.RES_2K) resPart = '-2k';
  if (resolution === Resolution.RES_4K) resPart = '-4k';

  const modelName = `${MODEL_IMAGE_BASE}-${ratioPart}${resPart}`;

  // 2. OpenAI Quality Parameter Mapping
  let quality = 'standard';
  if (resolution === Resolution.RES_4K) quality = 'hd';
  if (resolution === Resolution.RES_2K) quality = 'medium';

  // 3. Explicit Size for OpenAI Body
  const standardSize = getOpenAISize(aspectRatio);
  const strengthValue = getDenoisingStrength(motionStrength);

  try {
    const randomSeed = Math.floor(Math.random() * 4294967295);

    // List of ALL inputs (Reference + Context) for Multimodal understanding
    const allInputImages = [referenceImageDataUrl, ...contextImageDataUrls];

    const payload: any = {
        model: modelName,
        prompt: enhancedPrompt,
        response_format: "b64_json",
        seed: randomSeed,

        // --- OpenAI Standard Params ---
        quality: quality,
        size: standardSize,

        // --- Main Image for Structure (Img2Img) ---
        image: referenceImageDataUrl, 

        // --- Gemini/Banana Specifics ---
        extra_body: {
            // Precise Multimodal Input: List of all images to "see"
            input_images: allInputImages, 
            images: allInputImages, // Fallback for some proxies

            // Explicit Gemini Params
            image_size: resolution, 
            aspect_ratio: aspectRatio,
            strength: strengthValue, // Denoising strength for img2img
            safety_filter_level: "block_only_high"
        }
    };

    const response = await fetch(`${creds.baseUrl}/images/generations`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${creds.apiKey}`
      },
      body: JSON.stringify(payload),
      credentials: 'omit'
    });

    if (!response.ok) {
        await handleModelError(response);
    }

    const data = await response.json();
    let finalImageUrl = '';

    if (data.data && Array.isArray(data.data) && data.data.length > 0) {
        const firstItem = data.data[0];
        if (firstItem.b64_json) finalImageUrl = firstItem.b64_json;
        else if (firstItem.url) finalImageUrl = firstItem.url;
    } 
    else if (data.b64_json) finalImageUrl = data.b64_json;
    else if (data.url) finalImageUrl = data.url;

    if (finalImageUrl) {
        if (finalImageUrl.startsWith('http') || finalImageUrl.startsWith('data:image')) return finalImageUrl;
        return `data:image/png;base64,${finalImageUrl}`;
    }

    throw new Error("API thành công nhưng không tìm thấy ảnh trả về.");

  } catch (error) {
    console.error("Error generating frame:", error);
    const msg = error instanceof Error ? error.message : String(error);
    if (msg.includes("Failed to fetch") || msg.includes("NetworkError")) {
        handleFetchError(error, creds.baseUrl);
    }
    throw error;
  }
};

