 * NEW: OPTIMIZE PROMPT FOR CREATIVE MODE
 */
export const optimizeCreativePrompt = async (
    creds: ApiCredentials,
    userPrompt: string,
    imageUrls: string[] = [] 
): Promise<CreativePromptResult> => {
    // ... (logic remains same as previous, just keeping file complete)
    const systemInstruction = `You are a world-class AI Art Prompt Engineer.
    YOUR TASK: Analyze User Idea + Reference Images -> Create Detailed English Prompt + Vietnamese Explanation.
    OUTPUT JSON: { "english": "...", "vietnamese": "..." }`;

    const userContent: any[] = [
        { type: "text", text: `User Idea: "${userPrompt}"` }
    ];

    if (imageUrls && imageUrls.length > 0) {
        userContent.push({ type: "text", text: "\n\nReference Images for Style/Vibe:" });
        imageUrls.forEach((url) => {
            userContent.push({ type: "image_url", image_url: { url: url } });
        });
    }

    const messages = [
        { role: "system", content: systemInstruction },
        { role: "user", content: userContent }
    ];

    try {
        const response = await fetch(`${creds.baseUrl}/chat/completions`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${creds.apiKey}`
            },
            body: JSON.stringify({
                model: MODEL_REASONING,
                messages: messages,
                max_tokens: 1500,
                temperature: 0.7,
                response_format: { type: "json_object" } 
            }),
            credentials: 'omit'
        });

        if (!response.ok) throw new Error("Prompt Optimization failed");
        const data = await response.json();
        const content = data.choices?.[0]?.message?.content;

        if (!content) throw new Error("API trả về nội dung rỗng.");

        let parsed;
        try {
            const cleanContent = content.replace(/```json/g, '').replace(/```/g, '').trim();
            parsed = JSON.parse(cleanContent);
        } catch (parseError) {
             const firstOpen = content.indexOf('{');
            const lastClose = content.lastIndexOf('}');
            if (firstOpen !== -1 && lastClose !== -1) {
                parsed = JSON.parse(content.substring(firstOpen, lastClose + 1));
            } else {
                throw new Error("No JSON found");
            }
        }

        return {
            english: parsed.english || userPrompt,
            vietnamese: parsed.vietnamese || "Không thể dịch."
        };

    } catch (e) {
        return { 
            english: userPrompt, 
            vietnamese: `⚠️ Lỗi tối ưu: ${String(e)}. Dùng prompt gốc.` 
        };
    }
};

