import { AspectRatio, Resolution, GenerationMode, ApiCredentials, MotionStrength, ContextRole, CreativePromptResult } from "../types";
import { MODEL_REASONING, MODEL_IMAGE_BASE } from "../constants";

// Helper to convert file to Data URL
export const fileToDataUrl = async (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      resolve(reader.result as string);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const handleFetchError = (error: unknown, baseUrl: string) => {
    const msg = error instanceof Error ? error.message : String(error);
    if (msg.includes("Failed to fetch") || msg.includes("NetworkError")) {
        if (window.location.protocol === 'https:' && baseUrl.startsWith('http://')) {
            throw new Error(`Lỗi kết nối (Mixed Content): Trình duyệt chặn gọi HTTP API từ trang HTTPS. Vui lòng dùng Ngrok (HTTPS) hoặc chạy App ở localhost.`);
        }
        throw new Error(`Lỗi kết nối đến Server (${baseUrl}). Vui lòng kiểm tra CORS hoặc Server có đang chạy không.`);
    }
    throw error;
};

// Helper: Convert "16:9" to "16x9" for Banana Pro model naming
const getBananaRatio = (ratio: AspectRatio): string => {
    return ratio.replace(':', 'x');
};

// Helper: Construct Model Name based on Banana Pro Guide
// 1K: gemini-3-pro-image-{ratio}
// 2K/4K: gemini-3-pro-image-{res}-{ratio}
const getBananaModelName = (res: Resolution, ratio: AspectRatio): string => {
    const r = getBananaRatio(ratio);

    if (res === Resolution.RES_1K) {
        return `${MODEL_IMAGE_BASE}-${r}`;
    }

    // Convert "2K" -> "2k", "4K" -> "4k"
    const resString = res.toLowerCase();
    return `${MODEL_IMAGE_BASE}-${resString}-${r}`;
};

// Helper: Extract URL from Markdown/Text response
const extractUrlFromText = (text: string): string => {
    // Regex to find http/https urls
    const urlRegex = /(https?:\/\/[^\s)]+)/g;
    const match = text.match(urlRegex);

    if (match && match.length > 0) {
        // Clean trailing punctuation sometimes returned by LLMs
        let url = match[0];
        if (url.endsWith('.') || url.endsWith('"') || url.endsWith(')')) {
            url = url.slice(0, -1);
        }
        return url;
    }
    return "";
};

/**
 * Step 1: VISUAL DNA EXTRACTION & DIRECTOR AGENT
 * (Uses Flash for reasoning - Remains using Chat Completions)
 */
export const enhancePromptWithMotion = async (
  creds: ApiCredentials,
  prompt: string,
  duration: number,
  mode: GenerationMode,
  referenceImageDataUrl: string,
  contextImages: { url: string; role: ContextRole }[] = []
): Promise<string> => {

  const isForward = mode === GenerationMode.FIRST_TO_LAST;
  const targetFrameName = isForward ? 'LAST FRAME' : 'FIRST FRAME';
  const inputFrameName = isForward ? 'FIRST FRAME' : 'LAST FRAME';

  const systemInstruction = `You are an expert AI Video Director.
  CONTEXT: Input Image is ${inputFrameName}. Intent: "${prompt}". Duration: ${duration}s.
  VISUAL REF: Analyze the provided images for Face, Outfit, Style.
  TASK: Write a visual prompt for the ${targetFrameName}.
  OUTPUT: Only the prompt text.`;

  const userContent: any[] = [
    { type: "text", text: `MAIN REFERENCE (${inputFrameName}):` },
    { type: "image_url", image_url: { url: referenceImageDataUrl } }
  ];

  if (contextImages.length > 0) {
    userContent.push({ type: "text", text: "--- CONTEXT IMAGES ---" });
    contextImages.forEach((img, idx) => {
        userContent.push({ type: "text", text: `[${img.role.toUpperCase()}]` });
        userContent.push({ type: "image_url", image_url: { url: img.url } });
    });
  }

  userContent.push({ type: "text", text: `ACTION: "${prompt}"\nTarget: ${targetFrameName}.` });

  try {
    const response = await fetch(`${creds.baseUrl}/chat/completions`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${creds.apiKey}`
      },
      body: JSON.stringify({
        model: MODEL_REASONING,
        messages: [{ role: "system", content: systemInstruction }, { role: "user", content: userContent }],
        max_tokens: 1500,
        temperature: 0.7 
      }),
    });

    if (!response.ok) throw new Error(`Status ${response.status}`);
    const data = await response.json();
    return data.choices?.[0]?.message?.content || prompt;

  } catch (error) {
    console.warn("Optimization skipped due to error:", error);
    return prompt; 
  }
};

/**
 * Step 2: GENERATE VIDEO FRAME (Director Mode)
 * UPDATED: Uses Chat Completions with Specific Model Name
 */
export const generateVideoFrame = async (
  creds: ApiCredentials,
  enhancedPrompt: string,
  aspectRatio: AspectRatio,
  resolution: Resolution,
  referenceImageDataUrl: string, 
  motionStrength: MotionStrength,
  contextImageDataUrls: string[] = []
): Promise<string> => {

  try {
    // 1. Determine Logic: Text-to-Image vs Image-to-Image
    // Director mode ALWAYS has a reference image, so it is conceptually Image-to-Image.
    // However, the guide says: "Để chỉnh sửa ảnh sẵn có... dùng model gốc models/gemini-3-pro-image".
    // AND "Nếu tạo mới (dựa trên prompt)... dùng model có hậu tố".

    // In Director mode, we are "Generating a NEW frame based on an OLD one". 
    // This is technically Image-to-Image editing.
    // Let's try the Img2Img approach as per guide (using base model) first.

    const isImg2Img = true; 

    // Model Selection
    let modelName = "";
    if (isImg2Img) {
        // Guide: "Để chỉnh sửa ảnh sẵn có... dùng model models/gemini-3-pro-image"
        // But we want specific aspect ratios? The guide implies base model handles "edit".
        // Let's try to stick to the resolution-specific model if we treat it as "New Image with Reference".
        // If we want exact resolution control, we usually need the specific model.
        // Let's use the specific model for generation, passing the image as context.
        modelName = getBananaModelName(resolution, aspectRatio);
    }

    // Construct Payload
    // For Chat Completion Image Gen:
    // Prompt is text. Reference images are image_url.
    const messages: any[] = [
        { 
            role: "user", 
            content: [
                { type: "text", text: enhancedPrompt },
                { type: "image_url", image_url: { url: referenceImageDataUrl } },
                ...contextImageDataUrls.map(url => ({ type: "image_url", image_url: { url } }))
            ]
        }
    ];

    const response = await fetch(`${creds.baseUrl}/chat/completions`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${creds.apiKey}`
      },
      body: JSON.stringify({
        model: modelName,
        messages: messages,
        temperature: 0.7 
      }),
    });

    if (!response.ok) {
        const errText = await response.text();
        throw new Error(`API Error (${response.status}): ${errText}`);
    }

    const data = await response.json();
    const content = data.choices?.[0]?.message?.content || "";

    // Extract URL from text response
    const imageUrl = extractUrlFromText(content);

    if (imageUrl) return imageUrl;

    // Fallback: Check if there's an explicit image URL in a different format or if it failed silently
    if (content.includes("http")) {
        // Simple fallback extraction if regex missed something complex
        const parts = content.split(/\s+/);
        const link = parts.find((p: string) => p.startsWith("http"));
        if (link) return link;
    }

    console.error("No URL found in response:", content);
    throw new Error("AI đã trả về phản hồi nhưng không tìm thấy đường link ảnh.");

  } catch (error) {
    console.error("Director Gen Error:", error);
    handleFetchError(error, creds.baseUrl);
    throw error;
  }
};

