// Helper to convert file to Data URL
export const fileToDataUrl = async (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      resolve(reader.result as string);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const handleFetchError = (error: unknown, baseUrl: string) => {
    const msg = error instanceof Error ? error.message : String(error);
    if (msg.includes("Failed to fetch") || msg.includes("NetworkError")) {
        if (window.location.protocol === 'https:' && baseUrl.startsWith('http://')) {
            throw new Error(`Lỗi kết nối (Mixed Content): Trình duyệt chặn gọi HTTP API từ trang HTTPS. Vui lòng dùng Ngrok (HTTPS) hoặc chạy App ở localhost.`);
        }
        throw new Error(`Lỗi kết nối đến Server (${baseUrl}). Vui lòng kiểm tra CORS hoặc Server có đang chạy không.`);
    }
    throw error;
};

// Helper: Convert "16:9" to "16x9" for Banana Pro model naming
const getBananaRatio = (ratio: AspectRatio): string => {
    return ratio.replace(':', 'x');
};

// Helper: Construct Model Name based on Banana Pro Guide
const getBananaModelName = (res: Resolution, ratio: AspectRatio): string => {
    const r = getBananaRatio(ratio);
    if (res === Resolution.RES_1K) {
        return `${MODEL_IMAGE_BASE}-${r}`;
    }
    const resString = res.toLowerCase();
    return `${MODEL_IMAGE_BASE}-${resString}-${r}`;
};

// Helper: Extract URL from Markdown/Text response
const extractUrlFromText = (text: string): string => {
    const markdownRegex = /!\[.*?\]\((.*?)\)/;
    const mdMatch = text.match(markdownRegex);
    if (mdMatch && mdMatch[1]) return mdMatch[1];

    const urlRegex = /(https?:\/\/[^\s)"]+)/g;
    const matches = text.match(urlRegex);

    if (matches && matches.length > 0) {
        let url = matches[0];
        url = url.replace(/[).,;]+$/, "");
        return url;
    }
    return "";
};

// Helper: Robust JSON Cleaning and Parsing
const cleanJsonString = (str: string): string => {
    if (!str) return "{}";

    // 1. Remove Markdown code blocks
    let clean = str.replace(/```json/g, "").replace(/```/g, "").trim();

    // 2. Extract JSON object if embedded in text
    const firstOpen = clean.indexOf('{');
    const lastClose = clean.lastIndexOf('}');

    if (firstOpen !== -1 && lastClose !== -1) {
        clean = clean.substring(firstOpen, lastClose + 1);
    }

    return clean;
};

