): Promise<CreativePromptResult> => {
    // UPDATED INSTRUCTION: Emphasize description for Text-to-Image target
    const systemInstruction = `You are an AI Art Prompt Engineer.
    TASK: Analyze the Reference Images and User Idea to create a Master Prompt.

    CRITICAL GUIDELINES:
    1. TARGET: The output prompt will be used by a Text-to-Image model that CANNOT see the reference images. You MUST describe the visual style, colors, composition, and subject details from the references explicitly in the text.
    2. COLOR FIDELITY: Maintain the original color palette unless asked otherwise.

    OUTPUT FORMAT: Strictly JSON.
    Structure: { "english": "string", "vietnamese": "string" }`;

    // 1. Construct Multimodal Payload
    const userContentMultimodal: any[] = [{ type: "text", text: `Idea: "${userPrompt}"` }];
